mapper.select:

SELECT * FROM theme
JOIN routine ON theme.id = routine.theme_id
WHERE theme.id=#{id}

mapper.insert:
INSERT INTO routine(
    theme_id, repeated_on, is_active, start_time, end_time 
) VALUES (
    #{id},
    ARRAY[#{repeatedOn[0]}, #{repeatedOn[1]}, #{repeatedOn[2]}, #{repeatedOn[3]}, #{repeatedOn[4]}, #{repeatedOn[5]}, #{repeatedOn[6]}, #{repeatedOn[7]}]::DayType[],
    #{isActive}, #{startTime}, #{endTime}
);

mapper.update:
UPDATE routine
    SET 
        repeated_on = ARRAY[#{repeatedOn[0]}, #{repeatedOn[1]}, #{repeatedOn[2]}, #{repeatedOn[3]}, #{repeatedOn[4]}, #{repeatedOn[5]}, #{repeatedOn[6]}, #{repeatedOn[7]}]::DayType[],
        is_active = #{isActive}, start_time = #{startTime}, end_time = #{endTime}
    WHERE theme_id=#{id}
RETURNING 1;
